// Valida el header secret y extrae payload
const secret = $input.first().json.headers['x-ribuzz-secret'];
const expected = $env.RIBUZZ_WEBHOOK_SECRET;
if (!secret || secret !== expected) {
  throw new Error('Invalid webhook secret');
}
const body = $input.first().json.body;
if (!body?.job_id || !body?.diagnostic_id) {
  throw new Error('Missing job_id or diagnostic_id');
}
return [{ json: { job_id: body.job_id, diagnostic_id: body.diagnostic_id } }];

// Aplana respuestas variable_bd -> texto. Calcula métricas comerciales.
const answers = $input.all().map(i => i.json);
const flat = {};
for (const a of answers) {
  const vars = (a.variable_bd || '').split(',').map(v => v.trim());
  for (const v of vars) flat[v] = a.is_unknown ? '' : (a.answer_text || '');
}
function num(value, fallback = 0) {
  if (!value) return fallback;
  const clean = value.toString().toLowerCase().replace(/[$,\s]/g, '');
  const m = clean.match(/\d+(?:\.\d+)?(?:k|m|mm)?/g);
  if (!m) return fallback;
  const nums = m.map(x => { let n = parseFloat(x); if (x.endsWith('mm') || x.endsWith('m')) n *= 1e6; else if (x.endsWith('k')) n *= 1e3; return n; });
  return nums.length >= 2 ? (nums[0] + nums[1]) / 2 : nums[0];
}
const ventas = num(flat.comercial_ventas_mes);
const clientes = Math.max(num(flat.comercial_clientes_actuales, 1), 1);
const nuevos = num(flat.comercial_clientes_nuevos);
const inversion = num(flat.comercial_inversion_mes);
const leads = Math.max(num(flat.comercial_leads_mes, 1), 1);
const conv = num(flat.comercial_tasa_conversion);
const ticket_medio = ventas / clientes;
const cac = nuevos > 0 ? inversion / nuevos : inversion;
const ltv = ticket_medio * 12;
const ratio_cac_ticket = ticket_medio > 0 ? (cac / ticket_medio) * 100 : 100;
const ratio_cac_ltv = ltv > 0 ? (cac / ltv) * 100 : 100;
const leads_perdidos = Math.round(leads * (1 - conv / 100));
const conv_obj = Math.min(conv / 100 + 0.1, 1);
const clientes_adicionales = Math.round(leads * (conv_obj - conv / 100));
const ingreso_potencial = clientes_adicionales * ticket_medio;
const s_ticket = Math.min(ticket_medio / 1e6, 1) * 100;
const s_cac = Math.max(0, 100 - ratio_cac_ticket);
const s_conv = Math.min(conv * 2, 100);
const s_ltv_cac = Math.max(0, 100 - ratio_cac_ltv);
const salud_comercial = Math.round(s_ticket * 0.25 + s_cac * 0.3 + s_conv * 0.25 + s_ltv_cac * 0.2);
const metrics = {
  ticket_medio: Math.round(ticket_medio),
  cac: Math.round(cac),
  ltv: Math.round(ltv),
  ratio_cac_ticket: Math.round(ratio_cac_ticket * 10) / 10,
  ratio_cac_ltv: Math.round(ratio_cac_ltv * 10) / 10,
  leads_perdidos,
  ingreso_potencial: Math.round(ingreso_potencial),
  salud_comercial
};
const company = $('Fetch Diagnostic + Company').first().json;
return [{ json: { answers, flat, metrics, company } }];

// Parse P1 output (chainLlm returns $json.text directly)
const raw = $input.first().json.text;
const p1 = JSON.parse(raw.match(/\{[\s\S]*\}$/m)?.[0] || raw);
const metricsCtx = $('Code: Calculate Metrics').first().json;
return [{ json: { p1, metrics: metricsCtx.metrics, company: metricsCtx.company, p1_raw: raw } }];

// Combina los 4 scorers en un solo objeto scores
// chainLlm devuelve $json.text en lugar de $json.content[0].text
const items = $input.all();
const all = {};
for (const it of items) {
  const raw = it.json.text;
  if (!raw) continue;
  const parsed = JSON.parse(raw.match(/\{[\s\S]*\}$/m)?.[0] || raw);
  Object.assign(all, parsed.scores || {});
}
const values = Object.values(all);
const score_global = values.length ? (values.reduce((s, v) => s + v.score, 0) / values.length) : 0;
const ctx = $('Parse P1 + Prep Scorers').first().json;
return [{ json: { scores: all, score_global: Math.round(score_global * 10) / 10, p1: ctx.p1, metrics: ctx.metrics, company: ctx.company } }];

// chainLlm devuelve $json.text directamente
const raw = $input.first().json.text;
const fugas = JSON.parse(raw.match(/\{[\s\S]*\}$/m)?.[0] || raw);
const ctx = $('Combine 14 Scores').first().json;
return [{ json: { ...ctx, top_fugas: fugas.top_fugas || [] } }];

// Persistencia: consolida outputs de todos los agentes
// chainLlm devuelve .text en lugar de .content[0].text
const ctx = $('Parse Fugas').first().json;
const diagId = $('Validate Input').first().json.diagnostic_id;
const jobId = $('Validate Input').first().json.job_id;
const parse = (s) => JSON.parse(s.match(/\{[\s\S]*\}$/m)?.[0] || s);
const reporter     = parse($('Agente 4: Reporter').first().json.text);
const playbook     = parse($('Agente 5: Playbook').first().json.text);
const classification = parse($('Agente 6: Lead Classifier').first().json.text);
const review       = parse($('Agente 7: Quality Reviewer').first().json.text);
return [{ json: { diagnostic_id: diagId, job_id: jobId, ctx, reporter, playbook, classification, review } }];

const ctx = $input.first().json;

const PROMPTS = {
  '2A': "Eres el AGENTE 2A - SCORER DE PRODUCT-MARKET FIT de RiBuzz AI. Evalúas 4 variables: problema, solucion, icp, cliente_actual. ESCALA 1-5 (1=Crítico, 2=Débil, 3=Funcional, 4=Fuerte, 5=Escalable). REGLA ESPECIAL: si is_unknown=true -> score máximo 2. RÚBRICA: PROBLEMA: 1 no articula, 2 síntomas vagos, 3 problema claro impacto vago, 4 problema+impacto concreto, 5 cuantificado+urgente. SOLUCIÓN: 1 no explica, 2 vaga sin diferenciador, 3 diferenciador genérico, 4 diferenciador específico, 5 único+demostrable. ICP: 1 no sabe, 2 perfil amplio, 3 perfil sin patrón cierre, 4 perfil+sabe porqué cierra, 5 ICP+real alineados. CLIENTE ACTUAL: 1 sin clientes, 2 distintos sin patrón, 3 tiene sin común, 4 sabe perfil, 5 ICP=real. PARA CADA VARIABLE: score, estado, diagnostico (1 frase), impacto (1 frase), recomendacion (1 acción específica). Devuelve SOLO JSON: {scores:{problema:{score,estado,diagnostico,impacto,recomendacion}, solucion:{...}, icp:{...}, cliente_actual:{...}}}",
  '2B': "Eres el AGENTE 2B - SCORER DE MONETIZACIÓN de RiBuzz AI. Evalúas 4 variables: oferta, ecuacion_valor, ticket_medio, recurrencia. ESCALA 1-5. REGLA: is_unknown -> max 2. RÚBRICA: OFERTA: 1 sin oferta, 2 precio sin alcance, 3 precio+alcance sin resultado, 4 todo definido, 5 productizada+pública. ECUACIÓN VALOR: 1 no articula, 2 resultado vago, 3 resultado sin CTA, 4 resultado+CTA, 5 medible+automatizado+prueba. TICKET MEDIO: 1 muy bajo, 2 cubre sin margen, 3 margen mínimo, 4 margen para invertir, 5 alto+upsell+LTV. RECURRENCIA: 1 100% única, 2 algunos vuelven sin sistema, 3 espontáneo, 4 proceso activo, 5 sistema documentado. USA las métricas calculadas: ticket_medio, ratio_cac_ticket, ratio_cac_ltv para anclar el score de ticket_medio. PARA CADA: score, estado, diagnostico, impacto, recomendacion. Devuelve SOLO JSON: {scores:{oferta:{...}, ecuacion_valor:{...}, ticket_medio:{...}, recurrencia:{...}}}",
  '2C': "Eres el AGENTE 2C - SCORER DE ADQUISICIÓN de RiBuzz AI. Evalúas 3 variables: canal_adquisicion, cac, conversion. ESCALA 1-5. REGLA: is_unknown -> max 2. RÚBRICA: CANAL: 1 sin canal, 2 impredecible/referidos, 3 canal identificado no escalable, 4 predecible+sabe invertir, 5 multi-canal medido. CAC: 1 no sabe, 2 CAC>50% del ticket, 3 CAC 20-50%, 4 CAC<20%, 5 optimizado+decreciente. CONVERSIÓN: 1 no sabe tasa, 2 <10% sin saber porqué, 3 10-25% con cuellos, 4 >25% con proceso, 5 >40% documentado. USA las métricas: ratio_cac_ticket, ratio_cac_ltv, leads_perdidos. PARA CADA: score, estado, diagnostico, impacto, recomendacion. Devuelve SOLO JSON: {scores:{canal_adquisicion:{...}, cac:{...}, conversion:{...}}}",
  '2D': "Eres el AGENTE 2D - SCORER DE OPERACIONES de RiBuzz AI. Evalúas 3 variables: seguimiento, escalamiento, capacidad_ejecucion. ESCALA 1-5. REGLA: is_unknown -> max 2. RÚBRICA: SEGUIMIENTO: 1 sin seguimiento, 2 espontáneo, 3 proceso no documentado, 4 documentado, 5 CRM+secuencia. ESCALAMIENTO: 1 100% fundador, 2 mayoría fundador, 3 algunos documentados, 4 mitad documentado, 5 80%+ documentado. CAP. EJECUCIÓN: 1 nada, 2 mínimo <2h/sem, 3 básico parcial, 4 adecuado, 5 stack completo+equipo. PARA CADA: score, estado, diagnostico, impacto, recomendacion. Devuelve SOLO JSON: {scores:{seguimiento:{...}, escalamiento:{...}, capacidad_ejecucion:{...}}}"
};

return [
  { json: { scorer_id: '2A', system_prompt: PROMPTS['2A'], p1: ctx.p1, metrics: ctx.metrics, company: ctx.company } },
  { json: { scorer_id: '2B', system_prompt: PROMPTS['2B'], p1: ctx.p1, metrics: ctx.metrics, company: ctx.company } },
  { json: { scorer_id: '2C', system_prompt: PROMPTS['2C'], p1: ctx.p1, metrics: ctx.metrics, company: ctx.company } },
  { json: { scorer_id: '2D', system_prompt: PROMPTS['2D'], p1: ctx.p1, metrics: ctx.metrics, company: ctx.company } }
];
